 50→export type SmokeTestRuntime = AcceptanceTestRuntime;
 51→
 52→export type AcceptanceSuiteOptions = {
 53→  /** Extra env vars to set before the server boots (e.g. ORCHESTRATOR_MOCK_AGENT). */
 54→  env?: Record<string, string>;
 55→};
 56→
 57→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 58→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 59→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 60→
 61→export function setupAcceptanceSuite(
 62→  suiteName: string,
 63→  options?: AcceptanceSuiteOptions,
 64→): () => AcceptanceTestRuntime {
 65→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 66→  const namespace = `accept_${runId}`;
 67→  const suiteSlug = suiteName
 68→    .toLowerCase()
 69→    .replace(/[^a-z0-9]+/g, "_")
 70→    .replace(/^_+|_+$/g, "");
 71→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
 72→
 73→  let runtime: AcceptanceTestRuntime | undefined;
 74→  let server: ReturnType<typeof Bun.serve> | undefined;
 75→  let runtimeSurreal: Surreal | undefined;
 76→  let analyticsSurreal: Surreal | undefined;
 77→  let inflight: InflightTracker | undefined;
 78→  let setupSucceeded = false;
 79→
 80→  beforeAll(async () => {
 81→    // Apply env overrides before server boot
 82→    if (options?.env) {
 83→      for (const [k, v] of Object.entries(options.env)) {
 84→        process.env[k] = v;
 85→      }
 86→    }
 87→
 88→    const surreal = new Surreal();
 89→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
 90→    await withTimeout(
 91→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
 92→      10_000,
 93→      "authenticate with SurrealDB",
 94→    );
 95→
 96→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
 97→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
 98→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
 99→    await withTimeout(
100→      () => surreal.use({ namespace, database }),
101→      10_000,
102→      "switch to test namespace/database",
103→    );
104→
105→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
106→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
107→
108→    // Reserve a port so betterAuth gets the real URL at init time
109→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
110→    const reservedPort = tempServer.port;
111→    tempServer.stop(true);
112→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
113→
114→    const config: ServerConfig = {
115→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
116→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
117→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
118→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
119→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
120→      embeddingModelId: requireTestEnv("EMBEDDING_MODEL"),
121→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
122→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
123→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
124→      surrealUrl,
125→      surrealUsername,
126→      surrealPassword,
127→      surrealNamespace: namespace,
128→      surrealDatabase: database,
129→      port: reservedPort,
130→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
131→      betterAuthUrl: baseUrl,
132→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
133→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
134→      observerModelId: process.env.OBSERVER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
135→      scorerModelId: process.env.SCORER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
136→      anthropicApiUrl: process.env.ANTHROPIC_API_URL?.trim() || "https://api.anthropic.com",
137→      ...(process.env.ANTHROPIC_API_KEY?.trim() ? { anthropicApiKey: process.env.ANTHROPIC_API_KEY.trim() } : {}),
138→      inferenceProvider: "openrouter",
139→      selfHosted: process.env.SELF_HOSTED?.trim().toLowerCase() === "true",
140→      worktreeManagerEnabled: process.env.WORKTREE_MANAGER_ENABLED?.trim().toLowerCase() === "true",
141→    };
142→
143→    const deps = await createRuntimeDependencies(config);
144→    runtimeSurreal = deps.surreal;
145→    analyticsSurreal = deps.analyticsSurreal;
146→    inflight = createInflightTracker();
