import { describe, expect, it } from "bun:test";
import { setupAcceptanceSuite } from "../acceptance-test-kit";

const getRuntime = setupAcceptanceSuite("signup-guard", {
  env: {
    SELF_HOSTED: "true",
  },
});

describe("POST /api/auth/sign-up/email (SELF_HOSTED=true)", () => {
  it("returns 403 when signup is attempted in self-hosted mode", async () => {
    const { baseUrl } = getRuntime();
    const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        email: `test-${crypto.randomUUID()}@example.com`,
        password: "securepassword123",
        name: "Test User",
      }),
    });

    expect(response.status).toBe(403);
  });
});

content.thinking:
Found the culprit. The signup-guard test sets `SELF_HOSTED: "true"` via the `env` option. Looking back at the `setupAcceptanceSuite` code:

```typescript
// Apply env overrides before server boot
if (options?.env) {
  for (const [k, v] of Object.entries(options.env)) {
    process.env[k] = v;
  }
}
```

Line 82-86: It sets `process.env.SELF_HOSTED = "true"` but **never restores it**. Since bun runs tests in the same process, once the signup-guard test runs, ALL subsequent tests see `SELF_HOSTED=true` in `process.env`, which causes the signup guard to activate for their servers too.


The solution is to capture the original environment values before applying overrides in `beforeAll`, then restore them in `afterAll`. Let me check what cleanup is already happening in the test kit's `afterAll` hook.

