      },
      // MCP — Setup
      "/api/mcp/:workspaceId/projects": {
        GET: withTracing("GET /api/mcp/:workspaceId/projects", "GET", (request) =>
          mcpHandlers.handleListProjects(request.params.workspaceId),
        ),
