const lines = FILE_CONTENT.trim().split('\n');

const suites = new Set();
const errors = [];
let currentSuite = null;

for (const line of lines) {
  const match = line.match(/^acceptance-tests \(([^)]+)\)/);
  if (match) {
    currentSuite = match[1];
    suites.add(currentSuite);
  }

  if (line.includes('error:') || line.includes('(fail)') || line.includes('Expected')) {
    const msg = line.split('\t').pop().trim().slice(0, 200);
    errors.push(`[${currentSuite}] ${msg}`);
  }
}

console.log(`=== Failing suites (${suites.size}) ===`);
for (const s of [...suites].sort()) console.log(`  - ${s}`);

console.log(`\n=== Key errors (${Math.min(errors.length, 40)}/${errors.length}) ===`);
for (const e of errors.slice(0, 40)) console.log(e);

