const suites = new Set();
const failures = [];
let currentSuite = null;

for (const line of lines) {
  const match = line.match(/^acceptance-tests \(([^)]+)\)/);
  if (match) currentSuite = match[1];

  if (line.includes('(fail)')) {
    const msg = line.split('\t').pop().trim().slice(0, 250);
    failures.push(`[${currentSuite}] ${msg}`);
    suites.add(currentSuite);
  }
}

// Also look for error lines
const errors = [];
for (const line of lines) {
  const match = line.match(/^acceptance-tests \(([^)]+)\)/);
  if (match) currentSuite = match[1];

  if (line.toLowerCase().includes('error:') && !line.includes('endgroup')) {
    const msg = line.split('\t').pop().trim().slice(0, 250);
    errors.push(`[${currentSuite}] ${msg}`);
  }
}

